  User user = new(userId, command.Name, command.Email, actor);        await userRepository.AddAsync(user).ConfigureAwait(false);        if (!string.IsNullOrWhiteSpace(command.Password))        {            string hash = PasswordHasher.Hash(command.Password);            string salt = PasswordHashFormat.ExtractSalt(hash);            Auth auth = new(idGenerator.NextId(), userId, command.Email, hash, salt);            await authRepository.AddAsync(auth).ConfigureAwait(false);        }        return new IdCommandResult(userId.ToString());    }}